#!/usr/bin/env node

/**
 * @fileoverview Main executable entry point for the cli-share package.
 * It reads the raw captured terminal log generated by the shell wrapper,
 * parses command-line arguments for non-interactive execution (or falls back
 * to an interactive prompt), formats the raw log using the VT100 simulator,
 * handles GitHub OAuth authentication, and pushes the content as a GitHub Gist.
 * @module cli-share/cli
 */

const fs = require('fs');

async function main() {
  const inquirer = (await import('inquirer')).default;
  const chalk = (await import('chalk')).default;
  const open = (await import('open')).default;

  // Utilize the core package which exposes formatter, uploader, and auth utilities by default
  const core = require('@cli-share/core');
  const { format, uploadGist, getToken } = core;

  // 1. Read captured log from the environment or default paths (checking both new and old namespaces)
  const logPath = process.env.CLI_SHARE_LOG || process.env.AI_SHARE_LOG || 
                  (fs.existsSync('/tmp/cli-session.log') ? '/tmp/cli-session.log' : '/tmp/ai-session.log');

  if (!fs.existsSync(logPath)) {
    console.error(chalk.red('❌ Nothing captured. Start a session first. (' + logPath + ' not found)'));
    process.exit(1);
  }
  const rawLog = fs.readFileSync(logPath, 'utf8');

  if (!rawLog.trim()) {
    console.error(chalk.red('❌ Log is empty.'));
    process.exit(1);
  }

  // 2. Parse arguments for non-interactive conversational execution
  const args = process.argv.slice(2);
  let parsedMode = null;
  let parsedRange = null;
  let parsedVisibility = null;

  args.forEach(arg => {
    if (arg === '--full') parsedMode = 'Full Conversation';
    if (arg.startsWith('--range=')) {
      parsedMode = 'Custom Range';
      parsedRange = arg.split('=')[1];
    }
    if (arg === '--public') parsedVisibility = 'Public';
    if (arg === '--private') parsedVisibility = 'Private';
  });

  let answers = {};
  if (parsedMode && parsedVisibility && (parsedMode === 'Full Conversation' || (parsedMode === 'Custom Range' && parsedRange))) {
    answers = { mode: parsedMode, range: parsedRange, visibility: parsedVisibility };
  } else {
    // 3. Interactive prompts fallback
    answers = await inquirer.prompt([
      {
        type: 'list',
        name: 'mode',
        message: 'What to share?',
        choices: ['Full Conversation', 'Custom Range']
      },
      {
        type: 'input',
        name: 'range',
        message: 'Enter range (e.g. 3-15):',
        when: (a) => a.mode === 'Custom Range',
        validate: (v) => /^\d+-\d+$/.test(v) || 'Format: start-end (e.g. 3-15)'
      },
      {
        type: 'list',
        name: 'visibility',
        message: 'Visibility?',
        choices: ['Public', 'Private']
      }
    ]);
  }

  // 4. Format the raw VT100 terminal code sequence into pure readable markdown
  const content = format(rawLog, answers.range);

  // 5. Check content size to respect GitHub Gist API limits (1MB)
  if (content.length > 1_000_000) {
    console.error(chalk.yellow('⚠️  Log too large. Please select a custom range.'));
    process.exit(1);
  }

  // 6. Request Authentication Token (OAuth Device Flow or local credentials)
  const token = await getToken();

  // 7. Upload to GitHub Gists
  console.log(chalk.blue('⏳ Uploading to GitHub Gist...'));
  const url = await uploadGist(content, {
    token,
    isPublic: answers.visibility === 'Public',
    filename: `cli-chat-${Date.now()}.md`
  });

  // 8. Completion & User navigation
  console.log(chalk.green(`\n✅ Gist created: ${url}\n`));
  open(url);
}

main().catch((err) => {
  console.error(chalk.red(`❌ Fatal error: ${err.message}`));
  process.exit(1);
});
